import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Портування до 1.21.11","description":"Посібник з портування до останньої версії Minecraft.","frontmatter":{"title":"Портування до 1.21.11","description":"Посібник з портування до останньої версії Minecraft.","authors":["cassiancc"],"files":[]},"headers":[],"relativePath":"uk_ua/develop/porting/current.md","filePath":"translated/uk_ua/develop/porting/current.md","lastUpdated":1774101324000}`);var a={name:`uk_ua/develop/porting/current.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Портування до 1.21.11 <a class="header-anchor" href="#h1" aria-label="Permalink to “Портування до 1.21.11”">​</a></h1><p>Minecraft — це гра, яка постійно розвивається, нові версії змінюють гру таким чином, що впливає на розробників модів. Ця стаття охоплює загальні кроки, які можна виконати, щоб оновити свій мод до найновішої стабільної версії Minecraft.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>У цих документах обговорюється мігрування із <strong>1.21.10</strong> до <strong>1.21.11</strong>. Якщо ви шукаєте інше мігрування, перейдіть до цільової версії за допомогою спадного меню у верхньому правому куті.</p></div><h2 id="build-script" tabindex="-1">Оновлення скриптів збірки <a class="header-anchor" href="#build-script" aria-label="Permalink to “Оновлення скриптів збірки”">​</a></h2><p>Почніть з оновлення <code>gradle/wrapper/gradle-wrapper.properties</code>, <code>gradle.properties</code> і <code>build.gradle</code> вашого мода до останніх версій:</p><ol><li>Оновіть Gradle до останньої версії, виконавши таку команду: <code>./gradlew wrapper --gradle-version latest</code></li><li>Оновіть Minecraft, Завантажувач Fabric, Fabric Loom і Fabric API у <code>gradle.properties</code> (рекомендовано) або <code>build.gradle</code>. Знайдіть рекомендовані версії компонентів Fabric на <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">сайті розробки Fabric</a>.</li><li>Оновіть Gradle за допомогою кнопки оновлення у верхньому правому куті IntelliJ IDEA. Якщо цю кнопку не видно, ви можете примусово очистити кеші, запустивши <code>./gradlew --refresh-dependencies</code>.</li></ol><h2 id="porting-guides" tabindex="-1">Оновлення коду <a class="header-anchor" href="#porting-guides" aria-label="Permalink to “Оновлення коду”">​</a></h2><p>Після оновлення сценарію збірки до версії 1.21.11 ви можете переглянути свій мод і оновити будь-який змінений код, щоб зробити його сумісним з новою версією.</p><p>Щоб допомогти вам з оновленням, розробники модів задокументують зміни, на які вони натрапили, у статтях, як-от у блозі Fabric та в праймерах портування NeoForge.</p><ul><li><a href="https://fabricmc.net/2025/12/05/12111.html" target="_blank" rel="noreferrer"><em>Fabric для Minecraft 1.21.11</em> у блозі Fabric</a> містить пояснення високого рівня змін, внесених у Fabric API у 1.21.11.</li><li><a href="https://www.minecraft.net/en-us/article/minecraft-java-edition-1-21-11" target="_blank" rel="noreferrer"><em>Minecraft: Java Edition 1.21.11</em> у блозі Minecraft</a> є офіційним оглядом функцій, представлених у 1.21.11.</li><li><a href="https://minecraft.wiki/w/Java_Edition_1.21.11" target="_blank" rel="noreferrer"><em>Java Edition 1.21.11</em> на Minecraft Wiki</a> — це неофіційний короткий виклад вмісту оновлення.</li><li><a href="https://www.youtube.com/watch?v=5yY25GoWQhs&amp;pp=0gcJCSkKAYcqIYzv" target="_blank" rel="noreferrer">Новини пакетів даних і ресурсів від slicedlime у Minecraft 1.21.11</a> охоплює інформацію, пов’язану з оновленням даних вашого мода та вмісту пакету ресурсів.</li><li><a href="https://github.com/neoforged/.github/blob/main/primers/1.21.11/index.md" target="_blank" rel="noreferrer">Праймер NeoForge мігрування мода <em>Minecraft 1.21.10 -&gt; 1.21.11</em></a> охоплює перехід з 1.21.10 на 1.21.11, зосереджуючись лише на змінах коду. <ul><li>Будь ласка, зверніть увагу, що стаття, на яку посилається, є стороннім матеріалом, який не підтримується Fabric. Захищено авторським правом @ChampionAsh5357 і ліцензовано [Creative Commons Attribution 4.0 <a href="https://creativecommons.org/licenses/by/4.0/" target="_blank" rel="noreferrer">International</a>.</li></ul></li></ul>`,10)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};